unit lipdecide;

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

function REALCOMPARE(A, B: real): COMPTYPE;
var
  signA, signB: integer;
  absA, absB, maxAbs, temp, scale: real;
  expVal, i, scaleExp: integer;
  scaledA, scaledB: int64;
begin
  if A < 0.0 then
    signA := -1
  else if A > 0.0 then
    signA := 1
  else
    signA := 0;

  if B < 0.0 then
    signB := -1
  else if B > 0.0 then
    signB := 1
  else
    signB := 0;

  if signA < signB then
  begin
    REALCOMPARE := LT;
    exit;
  end
  else if signA > signB then
  begin
    REALCOMPARE := GT;
    exit;
  end
  else if signA = 0 then
  begin
    REALCOMPARE := EQ;
    exit;
  end;

  absA := abs(A);
  absB := abs(B);
  if absA > absB then
    maxAbs := absA
  else
    maxAbs := absB;

  if maxAbs = 0.0 then
  begin
    REALCOMPARE := EQ;
    exit;
  end;

  temp := maxAbs;
  expVal := 1;
  while temp >= 10.0 do
  begin
    temp := temp / 10.0;
    inc(expVal);
  end;
  while temp < 1.0 do
  begin
    temp := temp * 10.0;
    dec(expVal);
  end;

  scaleExp := 6 - expVal;
  scale := 1.0;
  if scaleExp > 0 then
  begin
    for i := 1 to scaleExp do
      scale := scale * 10.0;
  end
  else if scaleExp < 0 then
  begin
    for i := scaleExp to -1 do
      scale := scale / 10.0;
  end;

  scaledA := trunc(absA * scale + 0.5);
  scaledB := trunc(absB * scale + 0.5);

  if scaledA = scaledB then
  begin
    REALCOMPARE := EQ;
    exit;
  end;

  if signA > 0 then
  begin
    if scaledA < scaledB then
      REALCOMPARE := LT
    else
      REALCOMPARE := GT;
  end
  else
  begin
    if scaledA < scaledB then
      REALCOMPARE := GT
    else
      REALCOMPARE := LT;
  end;
end;

function PointsCoincide(i, j: integer): boolean;
begin
  PointsCoincide :=
    (REALCOMPARE(X[i], X[j]) = EQ) and
    (REALCOMPARE(Y[i], Y[j]) = EQ);
end;

function DistanceBetween(i, j: integer): real;
var
  dx, dy: real;
begin
  dx := X[j] - X[i];
  dy := Y[j] - Y[i];
  DistanceBetween := sqrt(dx * dx + dy * dy);
end;

function TriangleArea(i1, i2, i3: integer): real;
var
  value: real;
begin
  value := X[i1] * (Y[i2] - Y[i3]) +
           X[i2] * (Y[i3] - Y[i1]) +
           X[i3] * (Y[i1] - Y[i2]);
  TriangleArea := abs(value) / 2.0;
end;

function MinEnclosingCircleRadius(i1, i2, i3: integer): real;
var
  d12, d13, d23, maxDist, area2, radius: real;
begin
  d12 := DistanceBetween(i1, i2);
  d13 := DistanceBetween(i1, i3);
  d23 := DistanceBetween(i2, i3);

  maxDist := d12;
  if REALCOMPARE(d13, maxDist) = GT then
    maxDist := d13;
  if REALCOMPARE(d23, maxDist) = GT then
    maxDist := d23;

  area2 := abs(
    (X[i2] - X[i1]) * (Y[i3] - Y[i1]) -
    (Y[i2] - Y[i1]) * (X[i3] - X[i1]));

  if REALCOMPARE(area2, 0.0) = EQ then
  begin
    radius := maxDist / 2.0;
  end
  else
  begin
    radius := (d12 * d13 * d23) / (2.0 * area2);
  end;

  MinEnclosingCircleRadius := radius;
end;

function AngleCondition(i1, i2, i3: integer; epsilon: real): boolean;
var
  dx1, dy1, dx2, dy2: real;
  len1, len2, dotProd, cosTheta, cosLimit: real;
begin
  if PointsCoincide(i1, i2) or PointsCoincide(i3, i2) then
  begin
    AngleCondition := false;
    exit;
  end;

  dx1 := X[i1] - X[i2];
  dy1 := Y[i1] - Y[i2];
  dx2 := X[i3] - X[i2];
  dy2 := Y[i3] - Y[i2];

  len1 := sqrt(dx1 * dx1 + dy1 * dy1);
  len2 := sqrt(dx2 * dx2 + dy2 * dy2);

  if (REALCOMPARE(len1, 0.0) = EQ) or (REALCOMPARE(len2, 0.0) = EQ) then
  begin
    AngleCondition := false;
    exit;
  end;

  dotProd := dx1 * dx2 + dy1 * dy2;
  cosTheta := dotProd / (len1 * len2);

  if REALCOMPARE(cosTheta, 1.0) = GT then
    cosTheta := 1.0
  else if REALCOMPARE(cosTheta, -1.0) = LT then
    cosTheta := -1.0;

  cosLimit := cos(PI - epsilon);

  AngleCondition := REALCOMPARE(cosTheta, cosLimit) = GT;
end;

function PointToLineDistance(pt, firstIdx, lastIdx: integer): real;
var
  x1, y1, x2, y2, x0, y0: real;
  num, den, dx, dy: real;
begin
  x1 := X[firstIdx];
  y1 := Y[firstIdx];
  x2 := X[lastIdx];
  y2 := Y[lastIdx];
  x0 := X[pt];
  y0 := Y[pt];

  if (REALCOMPARE(x1, x2) = EQ) and (REALCOMPARE(y1, y2) = EQ) then
  begin
    dx := x0 - x1;
    dy := y0 - y1;
    PointToLineDistance := sqrt(dx * dx + dy * dy);
    exit;
  end;

  num := abs((y2 - y1) * x0 - (x2 - x1) * y0 + x2 * y1 - y2 * x1);
  dx := x2 - x1;
  dy := y2 - y1;
  den := sqrt(dx * dx + dy * dy);

  if REALCOMPARE(den, 0.0) = EQ then
    PointToLineDistance := 0.0
  else
    PointToLineDistance := num / den;
end;

function GetQuadrant(idx: integer): integer;
var
  cmpX, cmpY: COMPTYPE;
begin
  cmpX := REALCOMPARE(X[idx], 0.0);
  cmpY := REALCOMPARE(Y[idx], 0.0);

  if (cmpX = GT) or (cmpX = EQ) then
  begin
    if (cmpY = GT) or (cmpY = EQ) then
      GetQuadrant := 1
    else
      GetQuadrant := 4;
  end
  else
  begin
    if (cmpY = GT) or (cmpY = EQ) then
      GetQuadrant := 2
    else
      GetQuadrant := 3;
  end;
end;

procedure ComputeLICs;
var
  i, j, k: integer;
  dist, radius, areaVal: real;
  windowStart, windowEnd: integer;
  qCount: integer;
  quadrantSeen: array[1..4] of boolean;
  existsPart1, existsPart2: boolean;
begin
  { LIC 1 }
  CMV[1] := false;
  if NUMPOINTS >= 2 then
  begin
    for i := 1 to NUMPOINTS - 1 do
    begin
      dist := DistanceBetween(i, i + 1);
      if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
      begin
        CMV[1] := true;
        break;
      end;
    end;
  end;

  { LIC 2 }
  CMV[2] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      radius := MinEnclosingCircleRadius(i, i + 1, i + 2);
      if REALCOMPARE(radius, PARAMETERS.RADIUS1) = GT then
      begin
        CMV[2] := true;
        break;
      end;
    end;
  end;

  { LIC 3 }
  CMV[3] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      if AngleCondition(i, i + 1, i + 2, PARAMETERS.EPSILON) then
      begin
        CMV[3] := true;
        break;
      end;
    end;
  end;

  { LIC 4 }
  CMV[4] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - 2 do
    begin
      areaVal := TriangleArea(i, i + 1, i + 2);
      if REALCOMPARE(areaVal, PARAMETERS.AREA1) = GT then
      begin
        CMV[4] := true;
        break;
      end;
    end;
  end;

  { LIC 5 }
  CMV[5] := false;
  if (NUMPOINTS >= PARAMETERS.Q_PTS) then
  begin
    for windowStart := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
    begin
      for i := 1 to 4 do
        quadrantSeen[i] := false;
      for i := windowStart to windowStart + PARAMETERS.Q_PTS - 1 do
      begin
        j := GetQuadrant(i);
        quadrantSeen[j] := true;
      end;
      qCount := 0;
      for i := 1 to 4 do
        if quadrantSeen[i] then
          inc(qCount);
      if qCount > PARAMETERS.QUADS then
      begin
        CMV[5] := true;
        break;
      end;
    end;
  end;

  { LIC 6 }
  CMV[6] := false;
  if NUMPOINTS >= 2 then
  begin
    for i := 1 to NUMPOINTS - 1 do
    begin
      if REALCOMPARE(X[i + 1] - X[i], 0.0) = LT then
      begin
        CMV[6] := true;
        break;
      end;
    end;
  end;

  { LIC 7 }
  CMV[7] := false;
  if (NUMPOINTS >= 3) and (NUMPOINTS >= PARAMETERS.N_PTS) then
  begin
    for windowStart := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      windowEnd := windowStart + PARAMETERS.N_PTS - 1;
      for i := windowStart to windowEnd do
      begin
        dist := PointToLineDistance(i, windowStart, windowEnd);
        if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
        begin
          CMV[7] := true;
          break;
        end;
      end;
      if CMV[7] then
        break;
    end;
  end;

  { LIC 8 }
  CMV[8] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      j := i + PARAMETERS.K_PTS + 1;
      dist := DistanceBetween(i, j);
      if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
      begin
        CMV[8] := true;
        break;
      end;
    end;
  end;

  { LIC 9 }
  CMV[9] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1;
      k := j + PARAMETERS.B_PTS + 1;
      radius := MinEnclosingCircleRadius(i, j, k);
      if REALCOMPARE(radius, PARAMETERS.RADIUS1) = GT then
      begin
        CMV[9] := true;
        break;
      end;
    end;
  end;

  { LIC 10 }
  CMV[10] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
    begin
      j := i + PARAMETERS.C_PTS + 1;
      k := j + PARAMETERS.D_PTS + 1;
      if AngleCondition(i, j, k, PARAMETERS.EPSILON) then
      begin
        CMV[10] := true;
        break;
      end;
    end;
  end;

  { LIC 11 }
  CMV[11] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := j + PARAMETERS.F_PTS + 1;
      areaVal := TriangleArea(i, j, k);
      if REALCOMPARE(areaVal, PARAMETERS.AREA1) = GT then
      begin
        CMV[11] := true;
        break;
      end;
    end;
  end;

  { LIC 12 }
  CMV[12] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
    begin
      j := i + PARAMETERS.G_PTS + 1;
      if REALCOMPARE(X[j] - X[i], 0.0) = LT then
      begin
        CMV[12] := true;
        break;
      end;
    end;
  end;

  { LIC 13 }
  CMV[13] := false;
  if NUMPOINTS >= 3 then
  begin
    existsPart1 := false;
    existsPart2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      j := i + PARAMETERS.K_PTS + 1;
      dist := DistanceBetween(i, j);
      if not existsPart1 and (REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT) then
        existsPart1 := true;
      if not existsPart2 and (REALCOMPARE(dist, PARAMETERS.LENGTH2) = LT) then
        existsPart2 := true;
      if existsPart1 and existsPart2 then
        break;
    end;
    CMV[13] := existsPart1 and existsPart2;
  end;

  { LIC 14 }
  CMV[14] := false;
  if NUMPOINTS >= 5 then
  begin
    existsPart1 := false;
    existsPart2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1;
      k := j + PARAMETERS.B_PTS + 1;
      radius := MinEnclosingCircleRadius(i, j, k);
      if not existsPart1 and (REALCOMPARE(radius, PARAMETERS.RADIUS1) = GT) then
        existsPart1 := true;
      if not existsPart2 then
      begin
        if (REALCOMPARE(radius, PARAMETERS.RADIUS2) = LT) or
           (REALCOMPARE(radius, PARAMETERS.RADIUS2) = EQ) then
          existsPart2 := true;
      end;
      if existsPart1 and existsPart2 then
        break;
    end;
    CMV[14] := existsPart1 and existsPart2;
  end;

  { LIC 15 }
  CMV[15] := false;
  if NUMPOINTS >= 5 then
  begin
    existsPart1 := false;
    existsPart2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := j + PARAMETERS.F_PTS + 1;
      areaVal := TriangleArea(i, j, k);
      if not existsPart1 and (REALCOMPARE(areaVal, PARAMETERS.AREA1) = GT) then
        existsPart1 := true;
      if not existsPart2 and (REALCOMPARE(areaVal, PARAMETERS.AREA2) = LT) then
        existsPart2 := true;
      if existsPart1 and existsPart2 then
        break;
    end;
    CMV[15] := existsPart1 and existsPart2;
  end;
end;

procedure ComputePUM;
var
  i, j: integer;
begin
  for i := 1 to 15 do
    for j := 1 to 15 do
    begin
      if i = j then
        continue;
      case LCM[i, j] of
        NOTUSED:
          PUM[i, j] := true;
        ANDD:
          PUM[i, j] := CMV[i] and CMV[j];
        ORR:
          PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;
end;

procedure ComputeFUVAndLaunch;
var
  i, j: integer;
  allTrue: boolean;
begin
  for i := 1 to 15 do
  begin
    allTrue := true;
    for j := 1 to 15 do
    begin
      if not PUM[i, j] then
      begin
        allTrue := false;
        break;
      end;
    end;
    FUV[i] := (not PUM[i, i]) or allTrue;
  end;

  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      break;
    end;
  end;
end;

procedure DECIDE;
begin
  ComputeLICs;
  ComputePUM;
  ComputeFUVAndLaunch;
end;

end.
